import signal
import pytest
from source import bitcount


def test_bitcount_terminates_and_returns_correct_count():
    def _timeout(signum, frame):
        raise TimeoutError("bitcount did not terminate — likely infinite loop from XOR bug")

    signal.signal(signal.SIGALRM, _timeout)
    signal.alarm(2)
    try:
        result = bitcount(127)
        signal.alarm(0)
    except TimeoutError as e:
        pytest.fail(str(e))

    assert result == 7, (
        f"bitcount(127) should return 7 (0b1111111 has 7 set bits), got {result}"
    )
